mapper.select:
SELECT 'AGENT' AS reference_type, id::text AS reference_id, name AS reference_name, '/allowedTools' AS reference_path FROM agent WHERE COALESCE(allowed_tools, '[]'::jsonb) ?| ARRAY[
#{toolName}
]

SELECT 'INTENT_NODE' AS reference_type, id::text AS reference_id, name AS reference_name, '/allowedTools' AS reference_path FROM intent_node WHERE COALESCE(allowed_tools, '[]'::jsonb) ?| ARRAY[
#{toolName}
]

SELECT 'ASSISTANT_TEMPLATE' AS reference_type, id::text AS reference_id, name AS reference_name, '/allowedTools' AS reference_path FROM agent_template WHERE COALESCE(allowed_tools, '[]'::jsonb) ?| ARRAY[
#{toolName}
]

SELECT DISTINCT 'ASSISTANT_TEMPLATE_INTENT_NODE' AS reference_type, at.id::text AS reference_id, COALESCE(at.name, at.code) || ' / ' || COALESCE(node.node ->> 'name', node.node ->> 'code', 'unnamed') AS reference_name, '/intentTree/' || (node.ordinality - 1) || '/allowedTools' AS reference_path FROM agent_template at CROSS JOIN LATERAL jsonb_array_elements(at.intent_tree) WITH ORDINALITY AS node(node, ordinality) WHERE COALESCE(node.node -> 'allowedTools', '[]'::jsonb) ?| ARRAY[
#{toolName}
]
